mapper.sql:
SELECT regstDt , subscriberNo , subLinkName , contractNum , searchCntrNo , openAgntCd , openAgntNm , rwdProdCd , rwdProdNm , ifTrgtCd , ifTrgtNm , chnCd , chnNm , modelNm , modelId , reqBuyType , reqBuyTypeNm , imei , imeiTwo , scanId , vrfyRsltCd , vrfyRsltNm , resNo , vrfyId , vrfyDttm , rmk , buyPric , custNm , subStatusNm , openDt , rwdSeq FROM ( SELECT TO_CHAR(A.REGST_DTTM, 'YYYY-MM-DD') AS regstDt , B.SUBSCRIBER_NO AS subscriberNo , B.SUB_LINK_NAME AS subLinkName , B.CONTRACT_NUM AS contractNum , B.CONTRACT_NUM AS searchCntrNo , B.OPEN_AGNT_CD AS openAgntCd , FN_GET_ORGNM(B.OPEN_AGNT_CD) AS openAgntNm , A.RWD_PROD_CD AS rwdProdCd , FN_GET_RATENM(A.RWD_PROD_CD) AS rwdProdNm , A.IF_TRGT_CD AS ifTrgtCd , FN_GET_CODENM('CMN0260', A.IF_TRGT_CD) AS ifTrgtNm , A.CHN_CD AS chnCd , FN_GET_CODENM('CMN0249', A.CHN_CD) AS chnNm , B.MODEL_NAME AS modelNm , B.MODEL_ID AS modelId , C.REQ_BUY_TYPE AS reqBuyType , FN_GET_CODENM('RCP9004', C.REQ_BUY_TYPE) AS reqBuyTypeNm , A.IMEI AS imei , A.IMEI_TWO AS imeiTwo , B.SCAN_ID AS scanId , A.VRFY_RSLT_CD AS vrfyRsltCd , FN_GET_CODENM('CMN0261', A.VRFY_RSLT_CD) AS vrfyRsltNm , C.RES_NO AS resNo , A.VRFY_ID AS vrfyId , A.VRFY_DTTM AS vrfyDttm , A.RMK AS rmk , A.BUY_PRIC AS buyPric , B.SUB_LINK_NAME AS custNm , FN_GET_CODENM('MSP0003', B.SUB_STATUS) AS subStatusNm , B.LST_COM_ACTV_DATE AS openDt , A.RWD_SEQ AS rwdSeq FROM MSP_RWD_ORDER A , MSP_JUO_SUB_INFO B , MSP_REQUEST_DTL C , MSP_RWD_MST D , MSP_RWD_MEMBER E WHERE A.CONTRACT_NUM = B.CONTRACT_NUM AND A.CONTRACT_NUM = C.CONTRACT_NUM AND A.RWD_PROD_CD = D.RWD_PROD_CD AND A.RWD_SEQ = E.RWD_SEQ(+)
AND TO_CHAR(A.REGST_DTTM, 'YYYYMMDDHH24MISS') BETWEEN #{searchFromDt} || '000000' AND #{searchToDt} || '235959'
AND A.VRFY_RSLT_CD = #{searchRsltCd}
AND A.RWD_PROD_CD = #{searchRwdProdCd}
AND A.IF_TRGT_CD = #{searchIfTrgtCd}
AND A.CHN_CD = #{searchChnCd}
AND A.CONTRACT_NUM = #{searchVal}
AND B.SUB_LINK_NAME LIKE #{searchVal} || '%'
AND B.SUBSCRIBER_NO = REPLACE(#{searchVal},'-')
AND B.OPEN_AGNT_CD = #{agntId}
UNION ALL
SELECT TO_CHAR(A.REGST_DTTM, 'YYYY-MM-DD') AS regstDt , NVL(TRIM(C.CSTMR_MOBILE_FN) || TRIM(C.CSTMR_MOBILE_MN) || TRIM(C.CSTMR_MOBILE_RN), TRIM(C.CSTMR_TEL_FN) || TRIM(C.CSTMR_TEL_MN) || TRIM(C.CSTMR_TEL_RN)) AS subscriberNo , C.CSTMR_NAME AS subLinkName , B.CONTRACT_NUM AS contractNum , B.CONTRACT_NUM AS searchCntrNo , B.CNTPNT_SHOP_ID AS openAgntCd , FN_GET_ORGNM(B.CNTPNT_SHOP_ID) AS openAgntNm , A.RWD_PROD_CD AS rwdProdCd , FN_GET_RATENM(A.RWD_PROD_CD) AS rwdProdNm , A.IF_TRGT_CD AS ifTrgtCd , FN_GET_CODENM('CMN0260', A.IF_TRGT_CD) AS ifTrgtNm , A.CHN_CD AS chnCd , FN_GET_CODENM('CMN0249', A.CHN_CD) AS chnNm , E.PRDT_CODE AS modelNm , D.MODEL_ID AS modelId , B.REQ_BUY_TYPE AS reqBuyType , FN_GET_CODENM('RCP9004', B.REQ_BUY_TYPE) AS reqBuyTypeNm , A.IMEI AS imei , A.IMEI_TWO AS imeiTwo , B.SCAN_ID AS scanId , A.VRFY_RSLT_CD AS vrfyRsltCd , FN_GET_CODENM('CMN0261', A.VRFY_RSLT_CD) AS vrfyRsltNm , A.RES_NO AS resNo , A.VRFY_ID AS vrfyId , A.VRFY_DTTM AS vrfyDttm , A.RMK AS rmk , A.BUY_PRIC AS buyPric , C.CSTMR_NAME AS custNm , '' AS subStatusNm , '' AS openDt , A.RWD_SEQ AS rwdSeq FROM MSP_RWD_ORDER A , MCP_REQUEST@DL_MCP B , MCP_REQUEST_CSTMR@DL_MCP C , MCP_REQUEST_SALEINFO@DL_MCP D , CMN_INTM_MDL E WHERE A.REQUEST_KEY = B.REQUEST_KEY AND A.REQUEST_KEY = C.REQUEST_KEY AND A.REQUEST_KEY = D.REQUEST_KEY AND D.MODEL_ID = E.PRDT_ID(+) AND A.CONTRACT_NUM IS NULL
AND TO_CHAR(A.REGST_DTTM, 'YYYYMMDDHH24MISS') BETWEEN #{searchFromDt} || '000000' AND #{searchToDt} || '235959'
AND A.VRFY_RSLT_CD = #{searchRsltCd}
AND A.RWD_PROD_CD = #{searchRwdProdCd}
AND A.IF_TRGT_CD = #{searchIfTrgtCd}
AND A.CHN_CD = #{searchChnCd}
AND A.CONTRACT_NUM = #{searchVal}
AND C.CSTMR_NAME LIKE #{searchVal} || '%'
AND (C.CSTMR_MOBILE_FN || C.CSTMR_MOBILE_MN || C.CSTMR_MOBILE_RN LIKE '%'|| TRANSLATE(#{searchVal},'1234567890-','1234567890')||'%' OR C.CSTMR_TEL_FN || C.CSTMR_TEL_MN || C.CSTMR_TEL_RN LIKE '%'|| TRANSLATE(#{searchVal},'1234567890-','1234567890')||'%')
AND B.CNTPNT_SHOP_ID = #{agntId}
) ORDER BY rwdSeq DESC

SELECT B.SUBSCRIBER_NO AS subscriberNo , B.SUB_LINK_NAME AS subLinkName , B.CONTRACT_NUM AS contractNum , B.CONTRACT_NUM AS searchCntrNo , B.OPEN_AGNT_CD AS openAgntCd , FN_GET_ORGNM(B.OPEN_AGNT_CD) AS openAgntNm , A.RWD_PROD_CD AS rwdProdCd , FN_GET_RATENM(A.RWD_PROD_CD) AS rwdProdNm , B.LST_COM_ACTV_DATE AS lstComActvDate , A.STRT_DTTM AS strtDttm , A.END_DTTM AS endDttm , A.CHN_CD AS chnCd , FN_GET_CODENM('CMN0249', A.CHN_CD) AS chnNm , B.MODEL_NAME AS modelNm , B.MODEL_ID AS modelId , C.REQ_BUY_TYPE AS reqBuyType , FN_GET_CODENM('RCP9004', C.REQ_BUY_TYPE) AS reqBuyTypeNm , A.IMEI AS imei , A.IMEI_TWO AS imeiTwo , B.SCAN_ID AS scanId , C.RES_NO AS resNo , A.BUY_PRIC AS buyPric , B.SUB_LINK_NAME AS custNm , FN_GET_CODENM('MSP0003', B.SUB_STATUS) AS subStatusNm , B.LST_COM_ACTV_DATE AS openDt , A.RWD_SEQ AS rwdSeq , CAN_RSLT_CD AS canRsltCd , FN_GET_CODENM('CMN0262', A.CAN_RSLT_CD) AS canRsltNm , FN_GET_CODENM('CMN0265', A.RWD_STAT_CD) AS rwdStatCd , B.INTM_SRL_NO AS intmSrlNo , FN_GET_CODENM('CMN0259', (SELECT RWD_PRD FROM MSP_RWD_MST WHERE RWD_PROD_CD = A.RWD_PROD_CD)) AS rwdPrd FROM MSP_RWD_MEMBER A, MSP_JUO_SUB_INFO B, MSP_REQUEST_DTL C WHERE A.CONTRACT_NUM = B.CONTRACT_NUM AND A.CONTRACT_NUM = C.CONTRACT_NUM
AND A.STRT_DTTM BETWEEN #{searchFromDt} || '000000' AND #{searchToDt} || '235959'
AND A.RWD_STAT_CD = #{searchRsltCd}
AND A.RWD_PROD_CD = #{searchRwdProdCd}
AND A.CHN_CD = #{searchChnCd}
AND B.CONTRACT_NUM = #{searchVal}
AND B.SUB_LINK_NAME LIKE #{searchVal} || '%'
AND B.SUBSCRIBER_NO = REPLACE(#{searchVal},'-')
AND B.OPEN_AGNT_CD = #{agntId}
ORDER BY A.STRT_DTTM, B.SUB_LINK_NAME

mapper.select:
/* RwdMemberMapper.getRwdCntrInfo */ SELECT A.SUBSCRIBER_NO AS subscriberNo , A.CONTRACT_NUM AS contractNum , A.CONTRACT_NUM AS searchCntrNo , A.SUB_LINK_NAME AS custNm , A.SUB_STATUS AS subStatus , FN_GET_CODENM('MSP0003', A.SUB_STATUS) AS subStatusNm , A.OPEN_AGNT_CD AS openAgntCd , FN_GET_ORGNM(A.OPEN_AGNT_CD) AS openAgntNm , A.LST_COM_ACTV_DATE AS openDt , MRD.REQ_BUY_TYPE AS reqBuyType , A.MODEL_ID AS modelId , A.MODEL_NAME AS modelNm , A.IMEI AS imei , FN_GET_CODENM('RCP9004', MRD.REQ_BUY_TYPE) AS reqBuyTypeNm , MRD.RES_NO AS resNo , MRD.REQUEST_KEY AS requestKey FROM MSP_JUO_SUB_INFO A , MSP_REQUEST_DTL MRD WHERE A.CONTRACT_NUM = MRD.CONTRACT_NUM AND A.PPPO = 'PO' AND A.SUB_STATUS IN ('A', 'S')
AND A.SUBSCRIBER_NO = #{searchGbVal}
AND A.CONTRACT_NUM = #{searchGbVal}
AND rownum = 1

/* RwdMemberMapper.getRwdOrderCntrCnt */
SELECT COUNT(*)
  FROM MSP_RWD_ORDER
 WHERE (IF_TRGT_CD = 'Y' OR (IF_TRGT_CD = 'S' AND VRFY_RSLT_CD = 'Z'))
   AND CONTRACT_NUM = #{contractNum}

/* RwdMemberMapper.getRwdOrderImeiCnt */
SELECT COUNT(*)
  FROM MSP_RWD_ORDER
 WHERE (IF_TRGT_CD = 'Y' OR (IF_TRGT_CD = 'S' AND VRFY_RSLT_CD = 'Z'))
   AND (IMEI IN (#{imei}, #{imeiTwo}) OR IMEI_TWO IN (#{imei}, #{imeiTwo}))

  	AND NOT RWD_SEQ = #{rwdSeq}

/* RwdMemberMapper.getRwdMemCntrCnt */
SELECT COUNT(*)
FROM MSP_RWD_MEMBER
WHERE 1 = 1
  AND CONTRACT_NUM = #{contractNum}
  AND RWD_STAT_CD IN ('0', '1')

mapper.insert:
/* RwdMemberMapper.regMspRwdOrder */
INSERT INTO MSP_RWD_ORDER
(
	  RWD_SEQ
	, RWD_PROD_CD
	, RES_NO
	, REQUEST_KEY
	, CONTRACT_NUM
	, IF_TRGT_CD
	, CHN_CD
	, IMEI
	, IMEI_TWO
	, BUY_PRIC
	, RMK
	, REGST_ID
	, REGST_DTTM
	, RVISN_ID
	, RVISN_DTTM
)
VALUES
(
	  TO_CHAR(SYSDATE, 'YYYYMMDD') || TRIM(TO_CHAR(RWD_SEQ.NEXTVAL, '0000'))
	, #{sbscRwdProdNm}
	, #{resNo}
	, #{requestKey}
	, #{contractNum}
	, 'Y'

		, '3'


		, '1'

	, #{imei}
	, #{imeiTwo}
	, #{buyPric}
	, #{rmk}
    , #{sessionUserId}
	, SYSDATE
    , #{sessionUserId}
	, SYSDATE
)

mapper.select:
/* RwdMemberMapper.getOrderIfTrgtCd */
SELECT	IF_TRGT_CD
FROM    MSP_RWD_ORDER
WHERE   RWD_SEQ = #{rwdSeq}

mapper.update:
/* RwdMemberMapper.updateRwdOrder */
UPDATE MSP_RWD_ORDER
   SET IF_TRGT_CD = #{ifTrgtCd}
   	   , RVISN_ID = #{sessionUserId}
	   , RVISN_DTTM = SYSDATE

   	   , BUY_PRIC = #{buyPric}
       , IMEI = #{imei}
       , IMEI_TWO = #{imeiTwo}

 WHERE RWD_SEQ = #{rwdSeq}

/* RwdMemberMapper.deleteFile */
UPDATE MSP_RWD_ORDER
   SET FILE_ID = ''
     , FILE_DIR = ''
     , FILE_EXT = ''
 WHERE RWD_SEQ = #{rwdSeq, jdbcType=VARCHAR}

/* RwdMemberMapper.insertFile */
UPDATE MSP_RWD_ORDER
   SET FILE_EXT = #{ext, jdbcType=VARCHAR}	
     , FILE_DIR = #{realFilePath, jdbcType=VARCHAR}
     , FILE_ID  = #{realFileNm, jdbcType=VARCHAR}
 WHERE RWD_SEQ = #{rwdSeq, jdbcType=VARCHAR}

mapper.sql:
SELECT TO_CHAR(TO_DATE(BILL.BILL_YM, 'YYYYMM'), 'YYYY-MM') AS BILL_YM , SUB.SUBSCRIBER_NO , SUB.SUB_LINK_NAME AS CUST_NM , BILL.CONTRACT_NUM , FN_GET_CODENM('CMN0249', MEM.CHN_CD) AS CHN_NM , FN_GET_CODENM('CMN0258', MEM.RWD_PROD_CD) AS RWD_PROD_NM , FN_GET_CODENM('CLS0029', BILL.PYMN_CD) AS PYMN_CD , TO_CHAR(TO_DATE(BILL.BLPYM_DATE, 'YYYYMMDD'), 'YYYY-MM-DD') AS BLPYM_DATE , BILL.PYMN_AMNT , BILL.PYMN_MTHD_NM FROM MSP_RWD_BILL_OUT BILL, MSP_RWD_MEMBER MEM, MSP_JUO_SUB_INFO SUB WHERE BILL.CONTRACT_NUM = SUB.CONTRACT_NUM AND BILL.CONTRACT_NUM = MEM.CONTRACT_NUM
AND BILL.BILL_YM = #{searchBillYm}
AND MEM.RWD_PROD_CD = #{searchRwdProdCd}
AND MEM.CHN_CD = #{searchChnCd}
AND SUB.CONTRACT_NUM = #{searchVal}
AND SUB.SUB_LINK_NAME LIKE #{searchVal} || '%'
AND SUB.SUBSCRIBER_NO = REPLACE(#{searchVal},'-')
ORDER BY BILL.BILL_YM DESC, BILL.RWD_SEQ, BILL.RWD_BILL_OUT_SEQ

SELECT TO_CHAR(TO_DATE(CMPN.CMPN_DT, 'YYYYMMDD'), 'YYYY-MM-DD') AS CMPN_DT , SUB.SUBSCRIBER_NO , SUB.SUB_LINK_NAME AS CUST_NM , MEM.CONTRACT_NUM , FN_GET_CODENM('CMN0258', MEM.RWD_PROD_CD) AS RWD_PROD_NM , FN_GET_CODENM('CMN0264', CMPN.CMPN_STAT_CD) AS CMPN_STAT_CD , CMPN.BUY_PRIC , CMPN.RWD_RT , CMPN.FTR_PRIC , CMPN.OST_PRIC , CMPN.ASR_PRIC , CMPN.OST_RESN , CMPN.CNFM_LV , TO_CHAR(TO_DATE(CMPN.PAY_PLAN_DTTM, 'YYYYMMDD'), 'YYYY-MM-DD') AS PAY_PLAN_DTTM , TO_CHAR(CMPN.REGST_DTTM, 'YYYY-MM-DD HH24:MI:SS') AS REGST_DTTM , TO_CHAR(CMPN.RVISN_DTTM, 'YYYY-MM-DD HH24:MI:SS') AS RVISN_DTTM FROM MSP_RWD_CMPN CMPN, MSP_RWD_MEMBER MEM, MSP_JUO_SUB_INFO SUB WHERE CMPN.RWD_SEQ = MEM.RWD_SEQ AND MEM.CONTRACT_NUM = SUB.CONTRACT_NUM
AND CMPN.CMPN_DT BETWEEN #{searchFromDt} AND #{searchToDt}
AND CMPN.CMPN_STAT_CD = #{cmpnStatCd}
AND MEM.RWD_PROD_CD = #{searchRwdProdCd}
AND SUB.CONTRACT_NUM = #{searchVal}
AND SUB.SUB_LINK_NAME LIKE #{searchVal} || '%'
AND SUB.SUBSCRIBER_NO = REPLACE(#{searchVal},'-')
ORDER BY CMPN.CMPN_DT DESC
